// src/ToolsGraph.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { Pie, Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend,
  CategoryScale,
  LinearScale,
  BarElement
} from "chart.js";

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement);

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function ToolsGraph({ employee }) {
  const navigate = useNavigate();
  const [travelData, setTravelData] = useState([]);
  const [ticketData, setTicketData] = useState([]);
  const [month, setMonth] = useState("");
  const [year, setYear] = useState(new Date().getFullYear());

  useEffect(() => {
    if (employee?.empld) loadData();
  }, [employee]);

  const loadData = async () => {
    const resTravel = await fetch(
      `${apiBase}/travel-expenses?empld=${employee.empld}`
    );
    const travel = await resTravel.json();

    const resTicket = await fetch(
      `${apiBase}/ticket-expenses?empld=${employee.empld}`
    );
    const ticket = await resTicket.json();

    setTravelData(Array.isArray(travel) ? travel : []);
    setTicketData(Array.isArray(ticket) ? ticket : []);
  };

  const filterByMonth = (data) => {
    return data.filter((row) => {
      const d = new Date(row.travel_date || row.ticket_date);
      if (!month) return d.getFullYear() == year;
      return d.getFullYear() == year && d.getMonth() + 1 == month;
    });
  };

  const totalTravel = filterByMonth(travelData).reduce((sum, x) => sum + Number(x.amount), 0);
  const totalTicket = filterByMonth(ticketData).reduce((sum, x) => sum + Number(x.amount), 0);

  const pieData = {
    labels: ["Travel", "Ticket"],
    datasets: [
      {
        data: [totalTravel, totalTicket],
        backgroundColor: ["#4caf50", "#2196f3"]
      }
    ]
  };

  const barData = {
    labels: ["Travel", "Ticket"],
    datasets: [
      {
        label: "Amount",
        data: [totalTravel, totalTicket],
        backgroundColor: ["#4caf50", "#2196f3"]
      }
    ]
  };

  return (
    <div style={outer}>
      <div style={card}>
        {/* Header */}
        <div style={headerRow}>
          <button onClick={() => navigate("/tools")} style={backBtn}>⬅ Back</button>
          <h2 style={title}>Monthly Expense Graph</h2>
        </div>

        <p style={empInfo}>
          Employee: {employee.name} • {employee.empld}
        </p>

        {/* Filters */}
        <div style={filterBox}>
          <div>
            <span>Month</span>
            <select value={month} onChange={(e) => setMonth(Number(e.target.value))} style={inputBox}>
              <option value="">All Months</option>
              {[...Array(12)].map((_, i) => (
                <option value={i + 1}>{i + 1}</option>
              ))}
            </select>
          </div>

          <div>
            <span>Year</span>
            <input
              type="number"
              value={year}
              onChange={(e) => setYear(e.target.value)}
              style={inputBox}
            />
          </div>
        </div>

        {/* Pie Chart */}
        <h3 style={{ color: green }}>Pie Chart</h3>
        {totalTravel === 0 && totalTicket === 0 ? (
          <p>No expense data available.</p>
        ) : (
          <Pie data={pieData} />
        )}

        {/* Bar Chart */}
        <h3 style={{ color: green, marginTop: 20 }}>Bar Chart</h3>
        <Bar data={barData} />
      </div>
    </div>
  );
}

// -------- Styles ----------
const outer = {
  minHeight: "100vh",
  background: lightGreen,
  padding: 20
};
const card = {
  maxWidth: 900,
  background: "#fff",
  margin: "0 auto",
  padding: 20,
  borderRadius: 16,
  boxShadow: "0 6px 20px rgba(0,0,0,0.1)"
};
const headerRow = { display: "flex", alignItems: "center", gap: 10 };
const backBtn = { background: "none", border: "none", color: green, fontSize: 16, cursor: "pointer" };
const title = { color: green };
const empInfo = { fontSize: 13, color: "#555" };
const filterBox = { display: "flex", gap: 20, marginBottom: 20 };
const inputBox = {
  padding: 6,
  borderRadius: 6,
  border: "1px solid #ccc",
  marginTop: 5
};
